from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    subject_map = {}
    for triple in triples:
        if triple.subject not in subject_map:
            subject_map[triple.subject] = []
        subject_map[triple.subject].append((triple.predicate, triple.object))

    # Identify the main subject (likely an airport)
    airport_predicates = {
        "cityServed", "location", "runwayLength", "runwayName", "elevationAboveTheSeaLevel",
        "elevationAboveTheSeaLevelInFeet", "elevationAboveTheSeaLevelInMetres", "icaoLocationIdentifier",
        "iataLocationIdentifier", "locationIdentifier", "operatingOrganisation", "owner", "runwaySurfaceType",
        "1stRunwayLengthFeet", "1stRunwaySurfaceType", "3rdRunwayLengthFeet"
    }

    main_subject = None
    for subject, triples_list in subject_map.items():
        if any(pred in airport_predicates for pred, _ in triples_list):
            main_subject = subject
            break

    if not main_subject:
        main_subject = next(iter(subject_map.keys())) if subject_map else ""

    # Build a single natural-language sentence
    clauses = []
    secondary_entities = {}  # Track entities like countries/cities for relative clauses

    for subject, triples_list in subject_map.items():
        for predicate, obj in triples_list:
            if subject == main_subject:
                if predicate == "cityServed":
                    clauses.append(f"serves the city of {obj}")
                elif predicate == "location":
                    clauses.append(f"is located in {obj}")
                    secondary_entities[obj] = "location"
                elif predicate == "country":
                    clauses.append(f"is located in {obj}")
                    secondary_entities[obj] = "country"
                elif predicate == "elevationAboveTheSeaLevel":
                    clauses.append(f"has an elevation of {obj} metres above sea level")
                elif predicate == "elevationAboveTheSeaLevelInFeet":
                    clauses.append(f"has an elevation of {obj} feet above sea level")
                elif predicate == "elevationAboveTheSeaLevelInMetres":
                    clauses.append(f"has an elevation of {obj} metres above sea level")
                elif predicate == "runwayLength":
                    clauses.append(f"has a runway length of {obj} metres")
                elif predicate == "runwayName":
                    clauses.append(f"has a runway named {obj}")
                elif predicate == "runwaySurfaceType":
                    clauses.append(f"has a runway surface type of {obj}")
                elif predicate == "icaoLocationIdentifier":
                    clauses.append(f"has an ICAO identifier of {obj}")
                elif predicate == "iataLocationIdentifier":
                    clauses.append(f"has an IATA identifier of {obj}")
                elif predicate == "locationIdentifier":
                    clauses.append(f"has a location identifier of {obj}")
                elif predicate == "operatingOrganisation":
                    clauses.append(f"is operated by {obj}")
                elif predicate == "owner":
                    clauses.append(f"is owned by {obj}")
                elif predicate == "capital":
                    clauses.append(f"has {obj} as its capital")
                elif predicate == "isPartOf":
                    clauses.append(f"is part of {obj}")
                    secondary_entities[obj] = "isPartOf"
                elif predicate == "language":
                    # Language is a property of the country, not the airport
                    secondary_entities[obj] = "language"
                elif predicate == "leader":
                    clauses.append(f"has {obj} as its leader")
                elif predicate == "mayor":
                    clauses.append(f"has a mayor named {obj}")
                elif predicate == "nativeName":
                    clauses.append(f"has a native name of {obj}")
                elif predicate == "leaderParty":
                    clauses.append(f"has a leader party of {obj}")
                elif predicate == "1stRunwayLengthFeet":
                    clauses.append(f"has a first runway length of {obj} feet")
                elif predicate == "1stRunwaySurfaceType":
                    clauses.append(f"has a first runway surface type of {obj}")
                elif predicate == "3rdRunwayLengthFeet":
                    clauses.append(f"has a third runway length of {obj} feet")
            else:
                # Handle secondary entities (e.g., country has capital X)
                if predicate == "capital" and subject in secondary_entities:
                    clauses.append(f"whose capital is {obj}")
                elif predicate == "language" and subject in secondary_entities:
                    clauses.append(f"where the language is {obj}")
                elif predicate == "mayor" and subject in secondary_entities:
                    clauses.append(f"whose mayor is {obj}")

    # Construct the final sentence
    if not main_subject:
        return "."

    sentence = f"{main_subject}"
    if clauses:
        sentence += " " + ", ".join(clauses)

    return sentence + "."
